#include <print>
#include <cstring>

void safe_copy(char* dst, const char* src, const int capacity)
    pre(dst != nullptr)
    pre(src != nullptr)
    pre(capacity > 0)
{
    const int src_len = static_cast<int>(std::strlen(src));
    contract_assert(src_len < capacity);  // invariant inside the body
    std::memcpy(dst, src, src_len + 1);
}

int clamp(const int value, const int lo, const int hi)
    pre(lo <= hi)
    post(r: r >= lo)
    post(r: r <= hi)
{
    if (value < lo) return lo;
    if (value > hi) return hi;
    return value;
}

int main() {
    char buf[64];
    safe_copy(buf, "hello, world", 64);
    std::print("copied: {}\n", buf);

    std::print("clamp(15, 0, 10)  = {}\n", clamp(15, 0, 10));
    std::print("clamp(-5, 0, 10)  = {}\n", clamp(-5, 0, 10));
    std::print("clamp(7,  0, 10)  = {}\n", clamp(7, 0, 10));
