#include <print>
#include <vector>

int binary_search_idx(const std::vector<int>& v, const int target)
    pre(!v.empty())
    post(r: r == -1 || (r >= 0 && r < static_cast<int>(v.size())))
    post(r: r == -1 || v[r] == target)
{
    int lo = 0;
    int hi = static_cast<int>(v.size()) - 1;
    while (lo <= hi) {
        const int mid = lo + (hi - lo) / 2;
        contract_assert(mid >= 0 && mid < static_cast<int>(v.size()));
        if (v[mid] == target) return mid;
        if (v[mid] < target)  lo = mid + 1;
        else                  hi = mid - 1;
    }
    return -1;
}

int main() {
    const std::vector<int> v{1, 3, 5, 7, 9, 11, 13};
    std::print("search 7:  index {}\n", binary_search_idx(v, 7));
    std::print("search 1:  index {}\n", binary_search_idx(v, 1));
    std::print("search 13: index {}\n", binary_search_idx(v, 13));
    std::print("search 6:  index {}\n", binary_search_idx(v, 6));
}

