// std::contracts::contract_violation provides:
//   comment()  — predicate text as written in source (const char*)
//   location() — std::source_location: file, line, function
//   semantic() — active semantic (evaluation_semantic: 1=ignore 2=observe 3=enforce 4=quick_enforce)
