class Shape {
public:
    // Public non-virtual wrapper with contract — always checked,
    // regardless of the dynamic type of the object
    double area(const double scale) const
        pre(scale > 0.0)
        post(r: r >= 0.0)
    {
        return do_area() * scale;
    }
    virtual ~Shape() = default;
protected:
    virtual double do_area() const = 0;  // virtual hook without contract
};

class Circle : public Shape {
    double radius_;
public:
    explicit Circle(double r) : radius_(r) {}
protected:
    double do_area() const override {
        return 3.14159265 * radius_ * radius_;
    }
};

class Square : public Shape {
    double side_;
public:
    explicit Square(double s) : side_(s) {}
protected:
    double do_area() const override {
        return side_ * side_;
    }
};

int main() {
    Circle c{3.0};
    Square sq{4.0};

    std::printf("circle.area(2.0)  = %.2f\n", c.area(2.0));
    std::printf("square.area(0.5)  = %.2f\n", sq.area(0.5));

    // Through a base class pointer — same non-virtual wrapper,
    // same contracts as with a direct call
    Shape* s = &c;
    std::printf("via base ptr      = %.2f\n", s->area(1.0));

    // Violate pre(scale > 0.0)
    s->area(-1.0);
}

